// Claude API Response parsen
const claudeResponse = $input.first().json;

// Text-Content aus Claude Response extrahieren
let responseText = '';
if (claudeResponse.content && Array.isArray(claudeResponse.content)) {
  responseText = claudeResponse.content
    .filter(c => c.type === 'text')
    .map(c => c.text)
    .join('');
} else if (typeof claudeResponse.content === 'string') {
  responseText = claudeResponse.content;
}

// JSON aus der Antwort extrahieren
let analysisData;
try {
  // Versuche direktes JSON Parsing
  analysisData = JSON.parse(responseText);
} catch (e) {
  // Falls in Markdown Code Block eingebettet
  const jsonMatch = responseText.match(/```(?:json)?\s*([\s\S]*?)```/);
  if (jsonMatch) {
    analysisData = JSON.parse(jsonMatch[1].trim());
  } else {
    // Fallback: Versuche den groessten JSON-Block zu finden
    const jsonBlockMatch = responseText.match(/\{[\s\S]*\}/);
    if (jsonBlockMatch) {
      analysisData = JSON.parse(jsonBlockMatch[0]);
    } else {
      throw new Error('Konnte kein JSON in der Claude-Antwort finden: ' + responseText.substring(0, 200));
    }
  }
}

// Strukturierte Daten fuer Google Sheets aufbereiten
const rows = [];

// Commodity Topics
if (analysisData.commodity_topics) {
  for (const topic of analysisData.commodity_topics) {
    rows.push({
      analyse_typ: 'commodity',
      keyword_oder_thema: topic.keyword_oder_thema || topic.keyword || '',
      score: topic.score || 0,
      details: topic.details || '',
      kategorie: 'Commodity Topic'
    });
  }
}

// Differenzierungs-Themen
if (analysisData.differenzierung_themen) {
  for (const topic of analysisData.differenzierung_themen) {
    rows.push({
      analyse_typ: 'differenzierung',
      keyword_oder_thema: topic.keyword_oder_thema || topic.keyword || '',
      score: topic.score || 0,
      details: topic.details + (topic.abgedeckt_von ? ' | Abgedeckt von: ' + topic.abgedeckt_von.join(', ') : ''),
      kategorie: 'Differenzierung'
    });
  }
}

// Luecken
if (analysisData.luecken) {
  for (const topic of analysisData.luecken) {
    rows.push({
      analyse_typ: 'luecke',
      keyword_oder_thema: topic.keyword_oder_thema || topic.keyword || '',
      score: topic.score || 0,
      details: topic.details || '',
      kategorie: 'Content-Luecke'
    });
  }
}

// Zusammenfassung als eigene Zeile
if (analysisData.zusammenfassung) {
  rows.push({
    analyse_typ: 'zusammenfassung',
    keyword_oder_thema: 'Gesamtanalyse',
    score: 0,
    details: analysisData.zusammenfassung,
    kategorie: 'Zusammenfassung'
  });
}

return rows.map(row => ({ json: row }));
